In this appendix we state the Eulerian idempotents appearing in the cubature formulae constructed in Theorem \ref{theorem:deg_7_cubature_formula in the Lyndon basis. \begin{equation}\e(\epsilon_i) =\epsilon_i\end{equation}
\begin{equation}\e(\epsilon_i\epsilon_j) =\frac{1}{2}[\epsilon_i,\epsilon_j]\end{equation}
\begin{equation}\e(\epsilon_i\epsilon_j\epsilon_k) =\frac{1}{6}\Big (\big [\epsilon_i,[\epsilon_j,\epsilon_k]\big]+\big [[\epsilon_i,\epsilon_j],\epsilon_k\big] \Big )\end{equation}
\begin{equation}\e(\epsilon_i\epsilon_j\epsilon_k\epsilon_l) =\frac{1}{12}\Big (\big [\epsilon_i,\big [[\epsilon_j,\epsilon_k],\epsilon_l\big ]\big ]+\big [[\epsilon_i,\epsilon_j],[\epsilon_k,\epsilon_l]\big ]+\big [[\epsilon_i,\epsilon_k],[\epsilon_j,\epsilon_l]\big ]+\big [\big [\epsilon_i,[\epsilon_j,\epsilon_k]\big],\epsilon_l\big ]\Big )\end{equation}
\begin{equation}\e(\epsilon_i\epsilon_j\epsilon_k\epsilon_l\epsilon_m) =\frac{1}{60}\Big (12[\epsilon_i, [\epsilon_j, [\epsilon_k, [\epsilon_l, \epsilon_m]]]]+9[\epsilon_i, [\epsilon_j, [[\epsilon_k, \epsilon_m], \epsilon_l]]]+6[\epsilon_i, [[\epsilon_j, \epsilon_l], [\epsilon_k, \epsilon_m]]] +6[\epsilon_i, [[\epsilon_j, [\epsilon_l, \epsilon_m]], \epsilon_k]]+6[\epsilon_i, [[\epsilon_j, \epsilon_m], [\epsilon_k, \epsilon_l]]]+2[\epsilon_i, [[[\epsilon_j, \epsilon_m], \epsilon_l], \epsilon_k]] +3[[\epsilon_i, \epsilon_k], [\epsilon_j, [\epsilon_l, \epsilon_m]]]+[[\epsilon_i, \epsilon_k], [[\epsilon_j, \epsilon_m], \epsilon_l]]+2[[\epsilon_i, [\epsilon_k, \epsilon_l]], [\epsilon_j, \epsilon_m]] +3[[\epsilon_i, [\epsilon_k, [\epsilon_l, \epsilon_m]]], \epsilon_j]+2[[\epsilon_i, [\epsilon_k, \epsilon_m]], [\epsilon_j, \epsilon_l]]+[[\epsilon_i, [[\epsilon_k, \epsilon_m], \epsilon_l]], \epsilon_j] +3[[\epsilon_i, \epsilon_l], [\epsilon_j, [\epsilon_k, \epsilon_m]]]+[[\epsilon_i, \epsilon_l], [[\epsilon_j, \epsilon_m], \epsilon_k]]-[[[\epsilon_i, \epsilon_l], \epsilon_k], [\epsilon_j, \epsilon_m]] -[[[\epsilon_i, \epsilon_l], [\epsilon_k, \epsilon_m]], \epsilon_j]+2[[\epsilon_i, [\epsilon_l, \epsilon_m]], [\epsilon_j, \epsilon_k]]-[[[\epsilon_i, [\epsilon_l, \epsilon_m]], \epsilon_k], \epsilon_j] +3[[\epsilon_i, \epsilon_m], [\epsilon_j, [\epsilon_k, \epsilon_l]]]+[[\epsilon_i, \epsilon_m], [[\epsilon_j, \epsilon_l], \epsilon_k]]-[[[\epsilon_i, \epsilon_m], \epsilon_k], [\epsilon_j, \epsilon_l]] -[[[\epsilon_i, \epsilon_m], [\epsilon_k, \epsilon_l]], \epsilon_j]-[[[\epsilon_i, \epsilon_m], \epsilon_l], [\epsilon_j, \epsilon_k]]-2[[[[\epsilon_i, \epsilon_m], \epsilon_l], \epsilon_k], \epsilon_j]\Big )\end{equation}.}
